const staticData = $getWorkflowStaticData('global');

// Tokens desde Login_BTZ
const shortToken = $('Login_BTZ').first().json.shortToken;
const longToken  = $('Login_BTZ').first().json.token;

// ✅ Guardar en static data (bien)
staticData.btShort = shortToken;
staticData.btLong  = longToken;

// ✅ IMPORTANTÍSIMO: conservar el input (para no perder chatInput)
const input = $input.first().json;

// ✅ Return con MERGE: mantiene chatInput + agrega tokens
return [
  {
    json: {
      ...input,
      btToken: shortToken,
      btLongToken: longToken,
      ok: true,
    },
  },
];

// BTZ_Search_Stations (AI-SAFE)
// Entrada esperada (From AI): name (string)
// Salida requerida por n8n tool: { response: "texto" }

const term = String($input.first().json.name ?? '').trim().toUpperCase();

// Si no llega término, devolvemos instrucción corta (no catálogo completo)
if (!term) {
  return [{ json: { response: "Falta el parámetro 'name'. Ejemplo: name='MONTERREY'." } }];
}

// Aquí NO llamamos a Betterez desde Code Tool (porque Code Tool no hace HTTP).
// Este Tool es solo “formateador”. Para buscar en Betterez, necesitamos el HTTP tool filtrado.
// Por ahora: devuelve el término normalizado para que el agente lo use en el HTTP tool filtrado.
return [{ json: { response: `OK. Usar name=${term} para buscar estaciones.` } }];

